const Q_BIOLOGY_1995=[{"id": "objective>Biology>1995>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following does a virus have in common with animal cells?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">DNA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glycogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cytoplasm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both viruses and animal cells contain DNA. DNA, or deoxyribonucleic acid, is the molecule that contains the genetic code for all known living organisms and many viruses. The other options are not common to both viruses and animal cells. For example, viruses do not have a nucleus, cytoplasm, or glycogen.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1995>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organelles are likely to be present in cells that are actively respiring and photosynthesizing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nucleolus and centrioles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mitochondria and chloroplast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lysosomes and ribosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Golgi apparatus and endoplasmic reticulum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mitochondria and chloroplasts are the organelles involved in respiration and photosynthesis respectively. Mitochondria are the sites of cellular respiration, a process that generates ATP from the breakdown of sugars. Chloroplasts, on the other hand, are the sites of photosynthesis, a process that converts light energy into chemical energy in the form of glucose.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>1995>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One common characteristic of fungi, algae, mosses and ferns is that they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">show alternation of generations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproduce sexually by conjugation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">produce spores that are dispersed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possess chlorophyll in their tissues</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fungi, algae, mosses, and ferns all produce spores that are dispersed for reproduction. Spores are a common method of reproduction in these organisms. They are usually single-celled and are produced in large numbers. When conditions are favorable, the spores germinate and grow into new organisms.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI~~EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>1995>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Protein-like bodies are borne on the part labelled </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Spirogyra, the characteristic features include a spiral or helical chloroplast with embedded structures called pyrenoids. Pyrenoids are involved in the synthesis and storage of starch, and they appear as dense, protein-like bodies on the chloroplasts. <br/> Since the pyrenoids (protein-like bodies) are borne on the chloroplast, the correct label indicating where these structures are found is the chloroplast, which is labeled as II in the diagram. </div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1995>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The sexual reproductive function is performed by the part labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Spirogyra, sexual reproduction occurs through a process called conjugation. During conjugation, filaments of Spirogyra align side by side, and tube-like structures form between adjacent cells of the filaments, allowing the exchange of genetic material. <br/>  The cytoplasm (V) is where the sexual reproduction process occurs, as the genetic material from two different cells comes together and combines during conjugation.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>1995>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is transmitted through mosquito bite?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Filariasis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Typhus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plague</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Schistosomiasis</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Filariasis is a parasitic disease caused by an infection with roundworms of the Filarioidea type. These are spread by blood-feeding black flies and mosquitoes. This disease belongs to the group of diseases called helminthiases.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1995>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following insects lays its eggs in horny, purse-like cases?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Butterfly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Termite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cockroach</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cockroaches lay their eggs in horny, purse-like cases known as oothecae. The ootheca is a type of egg mass made by any member of a variety of species (usually insects or mollusks). The word is a Latinized combination of oo-, meaning 'egg', from the Greek word ōon (compare Latin ovum), and theca, meaning a 'cover' or 'container', from the Greek theke. Cockroaches, mantises, and other insects lay oothecae.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1995>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following vertebrates does the skin function as a respiratory surface?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lizard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Frog</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In frogs, the skin acts as a secondary respiratory surface. Gases can diffuse directly into the bloodstream because the skin is thin and moist. This is especially important when the frog is underwater and cannot access the surface to breathe air.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>1995>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Birds maintain their body temperature with the help of their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blood which maintains constant temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feathers which cover the body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skin which conserves moisture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">veins which transport fluid of constant temperature to all body tissues</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Birds have a constant body temperature which commonly remains in between 40°C to 45°C, even in sub-zero weather. The feathers play a very important function of retention of heat. The feathers create an efficient, non-conduction covering with its countless dead air spaces, useful as insulation.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1995>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary thickening in dicotyledonous stem is controlled by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cambium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pericycle</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary thickening in dicotyledonous stem is controlled by the cambium. The cambium is a type of plant tissue located between the xylem and the phloem in the stem and along the branches and roots of a plant. It is responsible for secondary growth in stems and roots, which results in an increase in thickness. The cambium produces new xylem and phloem cells, which pushes the older cells towards the center and the outside of the stem respectively, causing the stem to increase in diameter.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>1995>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>. The equation above represents a part of the light stage of photosynthesis. Which of the following must be presents for this reaction to occur?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Enzyme and light energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon dioxide and light energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Light energy and chlorophyll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlorophyll and enzyme</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equation 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(g) represents the photolysis of water, a part of the light-dependent reactions of photosynthesis. This process requires light energy and chlorophyll. Light energy is absorbed by chlorophyll, which then uses this energy to split water molecules into hydrogen and oxygen. The oxygen is released as a by-product, while the hydrogen is used in the light-independent reactions of photosynthesis.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>1995>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an experiment to investigate the effect of nitrogen on the growth of plants, the substrate should be a medium of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">washed sand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saw dust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cow dung</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay soil</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an experiment to investigate the effect of nitrogen on the growth of plants, the substrate should be a medium of washed sand. This is because washed sand is inert and does not contain any nutrients, allowing the experimenter to control the amount of nitrogen the plants receive.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>1995>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which vitamin plays an important role in blood clotting?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vitamin A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vitamin K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vitamin B<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vitamin C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vitamin K plays an important role in blood clotting. It is a fat-soluble vitamin that is involved in the production of several proteins necessary for blood clotting. Without sufficient vitamin K, the blood would not clot properly, which could lead to excessive bleeding.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>1995>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mammalian organ which acts both as a digestive and as an endocrine organ is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oesophagus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spleen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pancreas is a unique organ in the body that functions both as an endocrine and a digestive organ. As a digestive organ, it produces pancreatic juice which contains enzymes that help in the digestion of food. As an endocrine organ, it produces hormones like insulin and glucagon which help in the regulation of blood sugar levels.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>1995>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of following is NOT involved in the transport of substance in the body?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lymph</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plasma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Leucocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Erythrocytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Leucocytes, also known as white blood cells, are not involved in the transport of substances in the body. They are involved in the immune response and protecting the body against diseases.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>1995>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The end product of glycolysis in plants and animals is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pyruvic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">citric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aspartic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">malic acid</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Glycolysis is the metabolic pathway that converts glucose into pyruvate. The free energy released in this process is used to form the high-energy molecules ATP (adenosine triphosphate) and NADH (reduced nicotinamide adenine dinucleotide). Therefore, the end product of glycolysis in both plants and animals is pyruvic acid.</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>1995>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During respiration, air circulates round plant tissues via the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lenticels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stomata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guard cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intercellular spaces</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During respiration, air circulates around plant tissues via the intercellular spaces. These spaces are the areas between plant cells that allow for the exchange of gases such as oxygen and carbon dioxide. Lenticels, stomata, and guard cells are all involved in gas exchange, but the actual circulation of air occurs in the intercellular spaces.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>1995>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The excretory structure in the earthworm is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">malpighian tubule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flame cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nephridium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kidney</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The excretory structure in the earthworm is the nephridium. Nephridia are tubular excretory organs in many invertebrates such as annelids, including earthworms. They remove metabolic wastes from the creature's body.</div>", "topic": "EXCRETION : TYPES OF EXCRETORY STRUCTURES"}, {"id": "objective>Biology>1995>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the bending of the arm, the biceps muscles</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contracts and the triceps muscles relaxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> relaxes and the triceps muscles contracts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contracts and the triceps muscles contract</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relaxes and the triceps muscles relaxes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the bending of the arm, the biceps muscle contracts and the triceps muscle relaxes. This is due to the antagonistic muscle action where when one muscle (the agonist) contracts, the other muscle (the antagonist) relaxes to allow movement.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>1995>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a healthy shoot of a flowering plant is illuminated from one side, auxins, accumulate on the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">non-illuminated side of the shoot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">illuminated side of the shoot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upper side of the shoot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower side of the shoot</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Auxins are plant hormones that play a key role in phototropism, the growth of a plant in response to light. When a plant is illuminated from one side, auxins accumulate on the non-illuminated side of the shoot. This causes the cells on the non-illuminated side to elongate more than those on the illuminated side, causing the shoot to bend towards the light.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>1995>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The type of placentation shown is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">axial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parietal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">central</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marginal placentation is a type of placentation in which the placenta forms a ridge or margin along the ventral suture of the ovary. </div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>1995>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> An example of a plant having the placentation shown is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allamander</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hibiscus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water lily</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pride of Barbados</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"pride of Barbados\" (Caesalpinia pulcherrima), exhibits marginal placentation. This plant is part of the Fabaceae family, which commonly features marginal placentation. </div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>1995>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term caryopsis is used to describe a fruit in which the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">testa and pericarp are separate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seed and endocarp are fused</div>", "<div style=\"font-family:Cambria;font-size:17px;\">testa and pericarp are fused</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seed coat and fruit wall are impermeable</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A caryopsis is a small, simple fruit. It develops from a single pistil consisting of a single ovary. The pericarp and the seed coat are fused to form a covering over the entire seed. Examples are maize grain, rice, millet and guinea corn.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>1995>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sex of a foetus is determined during</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">meiosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fertilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">placentation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sex of a foetus is determined during fertilization. This is because the sex chromosomes that determine the sex of a foetus are carried in the sperm and egg cells, which combine during fertilization. The egg cell always carries an X chromosome, while the sperm cell carries either an X or a Y chromosome. If the sperm cell carries an X chromosome, the foetus will be female (XX), and if it carries a Y chromosome, the foetus will be male (XY).</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>1995>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Biological growth refers strictly to an increase in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protoplasm of an organism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of organisms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">size of an organism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development of form</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biological growth refers strictly to an increase in the protoplasm of an organism. Protoplasm is the living part of a cell that is often referred to as the 'physical basis of life'. An increase in protoplasm leads to an increase in cell size and number, which results in the growth of an organism. Therefore, biological growth is not just about the increase in size or number of organisms, but more specifically about the increase in the protoplasm of an organism.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>1995>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of walking is under the control of the part of the brain called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">optic lobe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">olfactory lobe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medulla oblongata</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of walking is under the control of the cerebellum. The cerebellum is a part of the brain that is responsible for motor control. It receives information from the sensory systems, the spinal cord, and other parts of the brain and then regulates motor movements. The cerebellum coordinates voluntary movements such as posture, balance, coordination, and speech, resulting in smooth and balanced muscular activity. It is also important for learning motor behaviors.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>1995>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gland directly affecting metabolic rate, growth and development is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adrenal land</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thyroid gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mammary gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parathyroid gland</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The thyroid gland directly affects metabolic rate, growth, and development. The thyroid gland is a butterfly-shaped organ located in the base of your neck. It releases hormones that control metabolism—the way your body uses energy. The thyroid's hormones regulate vital body functions, including breathing, heart rate, central and peripheral nervous systems, body weight, muscle strength, menstrual cycles, body temperature, and cholesterol levels.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>1995>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the  question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The diagram represents </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sensory neurone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relay neurone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">afferent neurone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motor neurone</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Motor neurones are cells in the brain and spinal cord that allow us to move, speak, swallow and breathe by sending commands from the brain to the muscles that carry out these functions.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>1995>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the  question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labelled X is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">axon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">terminal dendrites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synapse</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cell body. Also known as a soma, the cell body is the core section of the neuron. The cell body contains genetic information, maintains the neuron's structure, and provides energy to drive activities.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>1995>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following ions is involved in the conduction of the nerve impulse?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conduction of nerve impulses, also known as action potentials, is primarily facilitated by the movement of sodium (Na+) and potassium (K+) ions across the neuron's membrane. This process is known as the sodium-potassium pump. In the resting state, the neuron's membrane is polarized, with more positive charges outside than inside. When an action potential occurs, the membrane depolarizes, and Na+ ions rush into the neuron. This is followed by the repolarization phase, where K+ ions rush out of the neuron, restoring the membrane's polarity. Therefore, the correct answer is K+ ions.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>1995>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The depth of illumination in a water body can be measured with a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">photometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secchi disc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anemometer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The depth of illumination in a water body, also known as the photic zone or the depth to which light penetrates in the water, can be measured using a Secchi disc. A Secchi disc is a circular disc used to measure water transparency in oceans and lakes. The disc is lowered into the water until it is no longer visible, with the depth at which it disappears being recorded as the Secchi depth. Therefore, the correct answer is a Secchi disc.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>1995>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a food chain involving a primary producer, a primary consumer as well as a secondary consumer, the sharing of trophic energy is in the form that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the primary consumer has more energy than the primary producer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary consumer takes up all the energy contents of the primary consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy is shared equally between the three groups of organism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary consumer gets only a small portion of the energy contained in the primary producer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a food chain, energy is transferred from one trophic level to the next. However, not all energy is transferred. Only about 10% of the energy from one trophic level is transferred to the next. This is known as the 10% rule in ecology. Therefore, the secondary consumer gets only a small portion of the energy contained in the primary producer.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>1995>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In spite of the removal of carbon dioxide from the atmosphere, its amount remains more or less constant because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is produced by green plants during photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is produced during respiration of animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> it is absorbed inn ocean water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">green plants release it during the day</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of carbon dioxide in the atmosphere remains more or less constant because it is part of a cycle known as the carbon cycle. In this cycle, carbon dioxide is produced during the respiration of animals and other organisms. It is then absorbed by plants during photosynthesis, which convert it into organic compounds. These compounds are then consumed by animals, which respire and release carbon dioxide back into the atmosphere, completing the cycle.</div>", "topic": "RESPIRATION : AEROBIC RESPIRATION"}, {"id": "objective>Biology>1995>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a tropical rain forest, non-epiphytic ferns and allies occur as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">middle storey species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upper storey species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shade-loving species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emergent species</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Non-epiphytic ferns and allies in a tropical rain forest are shade-loving species. This is because they are adapted to grow in low light conditions under the canopy of the forest. They are not middle or upper storey species because they do not grow high up in the trees. They are also not emergent species because they do not stand out above the rest of the vegetation.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1995>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Colonization of a bare rock surface is termed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary succession</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary succession</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Colonization of a bare rock surface is termed primary succession. Primary succession is the series of community changes which occur on an entirely new habitat which has never been colonized before. For example, a newly quarried rock face or sand dunes. Evolution and specification are processes related to the development and diversification of species, not to the colonization of habitats. Secondary succession is the series of community changes which take place on a previously colonized, but disturbed or damaged habitat.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>1995>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a measure for the control of bilharzia?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cutting low brushes around homes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Application of molluscicides in water bodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Screening windows and doors with mosquito nets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Application of herbicides in water bodies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bilharzia, also known as schistosomiasis, is a disease caused by parasitic worms. One of the measures for the control of bilharzia is the application of molluscicides in water bodies. Molluscicides are chemicals used to kill snails and slugs. In the case of bilharzia, they are used to kill the snails that serve as intermediate hosts for the parasitic worms that cause the disease. The other options do not directly relate to the control of bilharzia.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1995>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Some of the diseases caused by bacteria are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tuberculosis, gonorrhoea and syphilis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tuberculosis, gonorrhoea and AIDS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Poliomyelitis, syphilis and gonorrhoea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AIDS, cholera and tuberculosis</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tuberculosis, gonorrhoea, and syphilis are all diseases caused by bacteria. Tuberculosis is caused by the bacterium Mycobacterium tuberculosis, gonorrhoea is caused by Neisseria gonorrhoeae, and syphilis is caused by Treponema pallidum. AIDS, on the other hand, is caused by a virus (HIV), not a bacterium.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1995>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Environmental pollutants which can work through the media of water, soil and air include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon monoxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">noise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">smoke</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur(IV)oxide is a type of environmental pollutant that can work through the media of water, soil, and air. It is a gas that can dissolve in water to form acid rain, which can then contaminate soil and bodies of water. Carbon monoxide is primarily an air pollutant, while noise and smoke are not typically associated with soil pollution.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>1995>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Human height is an example of a feature which depends on both</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">genotype and phenotype</div>", "<div style=\"font-family:Cambria;font-size:17px;\">genetic and environmental factors</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> mother's genotype and environmental factor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phenotipic and environmental factors</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Human height is an example of a feature that depends on both genetic and environmental factors. The genetic factor refers to the genes inherited from parents, which can influence the potential height a person can reach. The environmental factor refers to external influences such as nutrition and health, which can affect how much of that potential height is actually achieved. Genotype refers to the genetic makeup of an individual, while phenotype refers to the observable characteristics, such as height, which are influenced by both the genotype and the environment.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1995>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A person with type O blood can donate to a patient with type A because the donor's blood</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lacks antigens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lacks anti-A antibodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> lacks anti-B antibodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has both anti-A and anti-B antibodies</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A person with type O blood can donate to a patient with type A because the donor's blood lacks antigens. Blood type O is considered the universal donor because it lacks A and B antigens on the red blood cells, which means it can be donated to any of the other blood types (A, B, AB, and O) without causing an immune response.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1995>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The DNA molecule is a chain of repeating</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nucleosides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogenous bases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sugar phosphates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleotides</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The DNA molecule is a chain of repeating nucleotides. A nucleotide is the basic building block of nucleic acids, such as DNA and RNA. Each nucleotide consists of a sugar (deoxyribose in DNA), a phosphate group, and a nitrogenous base (adenine, thymine, cytosine, or guanine in DNA). The nucleotides are linked together in a chain through phosphodiester bonds between the sugar of one nucleotide and the phosphate of the next.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>1995>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The specific number of chromosomes in each somatic cell is represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">N</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">23</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The specific number of chromosomes in each somatic cell is represented by 2N. In humans, the diploid number (2N) is 46, which means there are 23 pairs of chromosomes in each somatic (body) cell. The symbol 'N' is used to represent the haploid number, which is the number of chromosomes in a gamete (sperm or egg cell).</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>1995>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man with blood group A is married to a woman with blood group A. Which of the following group combinations is possible if the family has three children?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">B, A, AB</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> O, A, B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">B, AB, AB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A, O, A</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A man and a woman with blood group A can have children with either blood group A or O. This is because the blood group A can be AA or AO, and the blood group O is OO. When the AO and AO combine, they can form AA (blood group A), AO (blood group A), or OO (blood group O). Therefore, the possible combinations for their three children could be A, O, A.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1995>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The F1 of a cross between a tall and a dwarf plant was tall. The F1 was advanced to F2. How many of 120 F2 plants will be dwarf?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a cross between a tall plant (TT) and a dwarf plant (tt), the F1 generation will all be tall (Tt) because the tall trait is dominant. When the F1 generation is self-fertilized to produce the F2 generation, the ratio of tall to dwarf plants will be 3:1. Therefore, out of 120 F2 plants, 1/4 (or 30) will be dwarf.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1995>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All the sons of a colour-blind woman will be coloured blind regardless of the state of the father because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the egg determines the phenotype of the son</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sons inherit the sex chromosome of their mothers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the father's sex chromosomes is weaker in sons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sex-linked traits express dominance in females</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Colour blindness is a sex-linked trait that is carried on the X chromosome. Women have two X chromosomes, so a colour-blind woman must have two colour-blindness genes (one on each X chromosome). Sons inherit one X chromosome from their mother and one Y chromosome from their father. Therefore, all sons of a colour-blind woman will inherit the colour-blindness gene from their mother and will be colour blind, regardless of the state of the father.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>1995>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The slender, long and slightly curved beak of the sun-bird is an adaptation for breeding for feeding on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nectar</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> small seeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">big seeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insects</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sun-bird has a long, slender, and slightly curved beak which is an adaptation for feeding on nectar. This type of beak allows the bird to reach deep into flowers to extract nectar, which is its primary food source.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1995>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Scales on reptiles are a feature for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conserving water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conserving food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protecting the skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">locomotion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Scales on reptiles serve several functions, one of which is to conserve water. Reptiles live in various environments, many of which are arid or semi-arid. Their scales are made of keratin and provide a waterproof barrier, preventing the loss of water through the skin.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1995>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The colour of the ventral surface of a fish is lighter than that of the dorsal. This is mainly</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an adaptation for movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an adaptation for camouflage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for attracting mates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for regulating body temperature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The coloration of a fish, with a lighter ventral surface and a darker dorsal surface, is a form of camouflage known as countershading. This makes the fish harder to see, both from above and below, protecting it from predators and allowing it to sneak up on prey.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1995>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The least evidence in support of the theory of evolution is provided by the study of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">anatomy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ecology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">embryology</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of evolution is supported by various scientific studies, including anatomy, geology, and embryology. However, ecology provides the least evidence in support of the theory of evolution. Ecology is the study of the interactions between organisms and their environment, and while it can provide some insights into evolutionary processes, it does not provide as direct or extensive evidence as the other fields mentioned.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>1995>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From which group of animals are the mammals generally believed to have most recently evolved?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reptiles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amphibians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Birds</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mammals are generally believed to have most recently evolved from a group of animals known as therapsids, or 'mammal-like reptiles', during the Mesozoic Era. Therefore, reptiles are the correct answer. Fish, amphibians, and birds are not considered direct ancestors of mammals in the evolutionary tree.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}];
